<div class="de">
<svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Südkoreas Blueprint für die Blockchain-Wirtschaft in H2 2026</text>
  <text x="20" y="50" fill="#71717a" font-size="13" font-family="sans-serif">Angekündigt bei der Kabinettssitzung am 13. Juli — vier Säulen</text>
  <rect x="20" y="70" width="28" height="28" rx="6" fill="#fb923c"/><text x="34" y="89" fill="#0a0a0a" font-size="14" font-weight="700" font-family="sans-serif" text-anchor="middle">1</text>
